import type { ErrorComponentProps } from "@tanstack/react-router";
import { Link, useRouter } from "@tanstack/react-router";
import { Button, Card } from "@workspace/ui";
import { AlertCircle, Home, RefreshCw } from "lucide-react";

function prettyPrintJson(value: unknown): string {
  try {
    return JSON.stringify(value, null, 2);
  } catch {
    return String(value);
  }
}

function describeError(error: unknown): {
  headline: string;
  summary: string | null;
  technical: string;
} {
  const fallback = {
    headline: "Something went wrong",
    summary: null as string | null,
    technical: "",
  };

  if (error instanceof Error) {
    const message = error.message.trim();
    const status =
      "status" in error &&
      typeof (error as { status?: unknown }).status === "number"
        ? (error as { status: number }).status
        : undefined;

    let summary: string | null = message || null;
    if (message.startsWith("{") || message.startsWith("[")) {
      try {
        const parsed = JSON.parse(message) as unknown;
        summary = prettyPrintJson(parsed);
      } catch {
        // keep raw message
      }
    }

    if (status === 401) {
      return {
        headline: "Session expired",
        summary: "Please sign in again to continue.",
        technical: message,
      };
    }

    return {
      headline: fallback.headline,
      summary,
      technical: message,
    };
  }

  return {
    headline: fallback.headline,
    summary: String(error),
    technical: String(error),
  };
}

export function RootError({ error, reset }: ErrorComponentProps) {
  const router = useRouter();
  const { headline, summary, technical } = describeError(error);
  const showDevPanel = import.meta.env.DEV && technical.length > 0;

  const handleRetry = () => {
    void router.invalidate();
    reset();
  };

  return (
    <div className="flex min-h-screen flex-col items-center justify-center bg-muted p-6 font-outfit">
      <Card className="w-full max-w-lg border-border/80 p-8 shadow-sm">
        <div className="flex flex-col items-center text-center">
          <div className="mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-destructive/10 text-destructive">
            <AlertCircle aria-hidden className="h-6 w-6" />
          </div>
          <h1 className="font-bold text-foreground text-xl">{headline}</h1>
          {summary ? (
            <p className="mt-3 max-w-md whitespace-pre-wrap text-muted-foreground text-sm leading-relaxed">
              {summary}
            </p>
          ) : (
            <p className="mt-3 text-muted-foreground text-sm leading-relaxed">
              An unexpected error occurred. You can try again or return home.
            </p>
          )}
        </div>

        <div className="mt-8 flex flex-col gap-2 sm:flex-row sm:justify-center">
          <Button
            className="gap-2"
            type="button"
            variant="default"
            onClick={handleRetry}
          >
            <RefreshCw className="h-4 w-4" />
            Try again
          </Button>
          <Button asChild className="gap-2" type="button" variant="outline">
            <Link to="/">
              <Home className="h-4 w-4" />
              Go home
            </Link>
          </Button>
        </div>

        {showDevPanel ? (
          <details className="mt-8 rounded-lg border border-border bg-card/50 text-left">
            <summary className="cursor-pointer px-3 py-2 font-medium text-muted-foreground text-xs uppercase tracking-wide">
              Technical details (development)
            </summary>
            <pre className="max-h-48 overflow-auto whitespace-pre-wrap break-words border-border border-t p-3 font-mono text-[11px] text-muted-foreground leading-relaxed">
              {technical}
            </pre>
          </details>
        ) : null}
      </Card>
    </div>
  );
}

